    <StepIndicator CurrentStep="currentStep" OnNavigate="GoToStep" />

    <CascadingValue Value="formState">
        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep OnNext="NextStep" OnBack="PreviousStep" />
                break;
