                 style="width:36px;height:36px;font-size:0.85rem;">
                @if (status == "completed")
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <small class="@(status == "pending" ? "text-muted" : "")">@StepNames[step]</small>
