@using sv_d4fe33bebd0c4f2487c71a1983df4780.Models

<div class="step-indicator d-flex justify-content-between mb-4 position-relative">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var status = step < CurrentStep ? "completed"
                   : step == CurrentStep ? "active"
                   : "pending";

        <div class="step-item text-center flex-fill @status"
             role="button"
             @onclick="() => OnStepClick(step)">
            <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center
                        rounded-circle @(status == "active" ? "bg-primary text-white" : status == "completed" ? "bg-success text-white" : "bg-light text-muted border")"
                 style="width:36px;height:36px;font-size:0.85rem;">
                @if (status == "completed")
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <small class="@(status == "pending" ? "text-muted" : "")">@StepNames[step]</small>
        </div>
    }
</div>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnNavigate { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigate.InvokeAsync(step);
        }
    }
}

