@using sv_d4fe33bebd0c4f2487c71a1983df4780.Models

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input class="form-control" @bind="FormState.FullName" placeholder="John Doe" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control @(emailError is not null ? "is-invalid" : "")"
           @bind="FormState.Email" placeholder="john@example.com" />
    @if (emailError is not null)
    {
        <div class="invalid-feedback">@emailError</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" @bind="FormState.Phone" placeholder="(555) 123-4567" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" @bind="FormState.Address" rows="2" placeholder="123 Main St, City, State ZIP"></textarea>
</div>

@if (validationError is not null)
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [CascadingParameter] public ApplicationFormState FormState { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private string? validationError;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (string.IsNullOrWhiteSpace(FormState.FullName) ||
            string.IsNullOrWhiteSpace(FormState.Email) ||
            string.IsNullOrWhiteSpace(FormState.Phone) ||
            string.IsNullOrWhiteSpace(FormState.Address))
        {
            validationError = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(FormState.Email);
            if (!emailValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

