@using sv_d4fe33bebd0c4f2487c71a1983df4780.Models

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < FormState.WorkEntries.Count; i++)
{
    var index = i;
    var entry = FormState.WorkEntries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @(index + 1)</h6>
                @if (FormState.WorkEntries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="entry.Company" placeholder="Company name" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="entry.Title" placeholder="Job title" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" @bind="entry.StartDate" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                </div>
                <div class="col-md-4 d-flex align-items-end mb-1">
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" @bind="entry.IsCurrent" id="@($"current-{index}")" />
                        <label class="form-check-label" for="@($"current-{index}")">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" @bind="entry.Description" rows="2" placeholder="Describe your responsibilities"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (validationError is not null)
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [CascadingParameter] public ApplicationFormState FormState { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddEntry()
    {
        FormState.WorkEntries.Add(new WorkEntryState());
    }

    private void RemoveEntry(int index)
    {
        FormState.WorkEntries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var entry in FormState.WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                validationError = "Company and job title are required for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_d4fe33bebd0c4f2487c71a1983df4780.Models

