                @if (FormState.References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="reference.Name" placeholder="Reference name" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="reference.Relationship" placeholder="e.g., Former Manager" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="reference.Email" placeholder="reference@example.com" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="reference.Phone" placeholder="(555) 123-4567" />
                </div>
            </div>
        </div>
    </div>
}

@if (FormState.References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (validationError is not null)
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [CascadingParameter] public ApplicationFormState FormState { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddReference()
    {
        if (FormState.References.Count < 3)
        {
            FormState.References.Add(new ReferenceState());
        }
    }

    private void RemoveReference(int index)
    {
        FormState.References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var r in FormState.References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                validationError = "All reference fields are required.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

