@using sv_d4fe33bebd0c4f2487c71a1983df4780.Models

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-2">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" @bind="FormState.CoverLetter" @bind:event="oninput"
              rows="12" maxlength="@MaxLength" placeholder="Tell us why you're a great fit for this role…"></textarea>
</div>

<div class="text-muted mb-3">
    @FormState.CoverLetter.Length / @MaxLength characters
</div>

@if (validationError is not null)
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [CascadingParameter] public ApplicationFormState FormState { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private async Task HandleNext()
    {
        validationError = null;

        if (string.IsNullOrWhiteSpace(FormState.CoverLetter))
        {
            validationError = "Please write a cover letter.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

